diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..874403a049f7 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,40 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Check for redundant comparison in OR/AND of fcmps with constants.
+  // (fcmp olt X, C1) || (fcmp olt X, C2) --> (fcmp olt X, C2) if C1 < C2
+  // (fcmp ogt X, C1) || (fcmp ogt X, C2) --> (fcmp ogt X, C1) if C1 < C2
+  // The less restrictive comparison dominates in OR, more restrictive in AND.
+  if (LHS0 == RHS0 && PredL == PredR) {
+    const APFloat *C1, *C2;
+    if (match(LHS1, m_APFloat(C1)) && match(RHS1, m_APFloat(C2))) {
+      APFloat::cmpResult CmpRes = C1->compare(*C2);
+      if (CmpRes == APFloat::cmpLessThan) {
+        // C1 < C2
+        // For olt: C2 is larger range (less restrictive for OR, more for AND)
+        // For ogt: C1 is larger range (less restrictive for OR, more for AND)
+        if (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_ULT) {
+          // olt/ult: smaller C = smaller range
+          return IsAnd ? LHS : RHS;
+        }
+        if (PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_UGT) {
+          // ogt/ugt: smaller C = larger range
+          return IsAnd ? RHS : LHS;
+        }
+      } else if (CmpRes == APFloat::cmpGreaterThan) {
+        // C1 > C2
+        if (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_ULT) {
+          // olt/ult: larger C = larger range
+          return IsAnd ? RHS : LHS;
+        }
+        if (PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_UGT) {
+          // ogt/ugt: larger C = smaller range
+          return IsAnd ? LHS : RHS;
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

